class AuthServiceServicer:
    """Implementation of the AuthService gRPC service."""

    def __init__(self, pb2_module):
        self.pb2 = pb2_module

    def Login(self, request, context):
        """Authenticate user and return a token."""
        print(f"[AuthService] Login attempt for user: {request.username}")

        user = store.users.get(request.username)
        if user and store.verify_password(request.password, user["password_hash"]):
            token, expires_at = store.generate_token(
                user["user_id"], user["username"], user["roles"]
            )
            print(f"[AuthService] Login successful for: {request.username}")
            return self.pb2.LoginResponse(
                success=True,
                token=token,
                message="Login successful",
                expires_at=expires_at,
            )
        else:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid username or password")
            print(f"[AuthService] Login failed for: {request.username}")
            return self.pb2.LoginResponse(
                success=False,
                token="",
                message="Invalid username or password",
                expires_at=0,
            )

    def ValidateToken(self, request, context):
        """Validate a JWT/session token."""
        print(f"[AuthService] Validating token")

        token_data = store.validate_token(request.token)
        if token_data:
            return self.pb2.TokenResponse(
                valid=True,
                user_id=token_data["user_id"],
                username=token_data["username"],
                roles=token_data["roles"],
            )
        else:
            return self.pb2.TokenResponse(
                valid=False, user_id="", username="", roles=[]
            )

    def Register(self, request, context):
        """Register a new user."""
        print(f"[AuthService] Registration attempt for: {request.username}")

        if request.username in store.users:
            context.set_code(grpc.StatusCode.ALREADY_EXISTS)
            context.set_details("Username already exists")
            return self.pb2.RegisterResponse(
                success=False, user_id="", message="Username already exists"
            )

        user_id = f"usr_{uuid.uuid4().hex[:8]}"
        new_user = {
            "user_id": user_id,
            "username": request.username,
            "email": request.email,
            "full_name": request.full_name,
            "password_hash": store._hash_password(request.password),
            "roles": ["user"],
            "created_at": int(time.time()),
            "is_active": True,
        }

        with store._lock:
            store.users[request.username] = new_user
            store.user_data[user_id] = {
                "preferences": {"theme": "light", "language": "en"},
                "activity": {"last_login": "never", "login_count": "0"},
            }

        print(f"[AuthService] User registered: {request.username} ({user_id})")
        return self.pb2.RegisterResponse(
            success=True, user_id=user_id, message="Registration successful"
        )

    def Logout(self, request, context):
        """Invalidate a user's session token."""
        print(f"[AuthService] Logout request")

        if store.invalidate_token(request.token):
            return self.pb2.LogoutResponse(
                success=True, message="Logged out successfully"
            )
        else:
            return self.pb2.LogoutResponse(
                success=False, message="Token not found or already expired"
            )


class DataServiceServicer:
    """Implementation of the DataService gRPC service."""

    def __init__(self, pb2_module):
        self.pb2 = pb2_module

    def _find_user_by_id(self, user_id):
        """Helper to find a user by their ID."""
        for user in store.users.values():
            if user["user_id"] == user_id:
                return user
        return None

    def GetUser(self, request, context):
        """Retrieve a single user by ID."""
        print(f"[DataService] GetUser request for: {request.user_id}")

        user = self._find_user_by_id(request.user_id)
        if user:
            return self.pb2.UserResponse(
                user_id=user["user_id"],
                username=user["username"],
                email=user["email"],
                full_name=user["full_name"],
                created_at=user["created_at"],
                is_active=user["is_active"],
            )
        else:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"User {request.user_id} not found")
            return self.pb2.UserResponse()

    def ListUsers(self, request, context):
        """List users with pagination and optional filtering."""
        print(
            f"[DataService] ListUsers request - page: {request.page}, "
            f"size: {request.page_size}, filter: '{request.filter}'"
        )

        page = max(request.page, 1)
        page_size = min(max(request.page_size, 1), 100)

        all_users = list(store.users.values())

        if request.filter:
            filter_lower = request.filter.lower()
            all_users = [
                u
                for u in all_users
                if filter_lower in u["username"].lower()
                or filter_lower in u["full_name"].lower()
                or filter_lower in u["email"].lower()
            ]

        total_count = len(all_users)
        start = (page - 1) * page_size
        end = start + page_size
        paginated = all_users[start:end]

        user_responses = [
            self.pb2.UserResponse(
                user_id=u["user_id"],
                username=u["username"],
                email=u["email"],
                full_name=u["full_name"],
                created_at=u["created_at"],
                is_active=u["is_active"],
            )
            for u in paginated
        ]

        return self.pb2.ListUsersResponse(
            users=user_responses,
            total_count=total_count,
            page=page,
            page_size=page_size,
        )

    def GetUserData(self, request, context):
        """Retrieve typed data associated with a user."""
        print(
            f"[DataService] GetUserData for user: {request.user_id}, "
            f"type: {request.data_type}"
        )

        user_data = store.user_data.get(request.user_id)
        if user_data is None:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"No data found for user {request.user_id}")
            return self.pb2.UserDataResponse()

        data = user_data.get(request.data_type, {})
        return self.pb2.UserDataResponse(
            user_id=request.user_id,
            data_type=request.data_type,
            data=data,
        )

    def StreamUserUpdates(self, request, context):
        """Server-streaming RPC for real-time user updates."""
        print(f"[DataService] StreamUserUpdates started for user: {request.user_id}")

        update_types = ["profile_update", "login", "data_change", "notification"]
        update_count = 0

        try:
            while context.is_active() and update_count < 10:
                time.sleep(2)
                update_count += 1

                update_type = update_types[update_count % len(update_types)]
                payload = json.dumps(
                    {
                        "event_id": str(uuid.uuid4()),
                        "detail": f"Simulated {update_type} event #{update_count}",
                        "user_id": request.user_id,
                    }
                )

                yield self.pb2.UserUpdate(
                    user_id=request.user_id,
                    update_type=update_type,
                    payload=payload,
                    timestamp=int(time.time()),
                )
                print(
                    f"[DataService] Sent update #{update_count} "
                    f"({update_type}) for user: {request.user_id}"
                )
        except Exception as e:
            print(f"[DataService] Stream error: {e}")

        print(f"[DataService] Stream ended for user: {request.user_id}")


class AuthInterceptor(grpc.ServerInterceptor):
    """Server interceptor for logging and optional auth checking."""

    OPEN_METHODS = {
        "/microservices.AuthService/Login",
        "/microservices.AuthService/Register",
    }

    def intercept_service(self, continuation, handler_call_details):
        method = handler_call_details.method
        print(f"[Interceptor] Incoming call: {method}")

        # For open methods, pass through without auth check
        if method in self.OPEN_METHODS:
            return continuation(handler_call_details)

        # For other methods, we could add token validation from metadata
        # For development, we pass through all requests
        return continuation(handler_call_details)


def serve(port=50051, max_workers=10):
    """Start the gRPC server."""

    # Try to compile and import proto modules
    if not os.path.exists("service_pb2.py") or not os.path.exists(
        "service_pb2_grpc.py"
    ):
        if not compile_proto():
            print("ERROR: Cannot compile proto files. Please install grpcio-tools:")
            print("  pip install grpcio grpcio-tools")
            sys.exit(1)

    import service_pb2
    import service_pb2_grpc

    # Create gRPC server with thread pool
    interceptors = [AuthInterceptor()]
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        interceptors=interceptors,
        options=[
            ("grpc.max_send_message_length", 50 * 1024 * 1024),
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),
            ("grpc.keepalive_time_ms", 30000),
            ("grpc.keepalive_timeout_ms", 10000),
            ("grpc.keepalive_permit_without_calls", True),
        ],
    )

    # Register service implementations
    auth_servicer = AuthServiceServicer(service_pb2)
    data_servicer = DataServiceServicer(service_pb2)

    service_pb2_grpc.add_AuthServiceServicer_to_server(auth_servicer, server)
    service_pb2_grpc.add_DataServiceServicer_to_server(data_servicer, server)

    # Enable server reflection for development tools like grpcurl
    try:
        from grpc_reflection.v1alpha import reflection

        SERVICE_NAMES = (
            service_pb2.DESCRIPTOR.services_by_name["AuthService"].full_name,
            service_pb2.DESCRIPTOR.services_by_name["DataService"].full_name,
            reflection.SERVICE_NAME,
        )
        reflection.enable_server_reflection(SERVICE_NAMES, server)
        print("[Server] Reflection enabled")
    except ImportError:
        print("[Server] grpcio-reflection not installed, skipping reflection")

    # Bind to port
    bind_address = f"[::]:{port}"
    server.add_insecure_port(bind_address)

    # Start server
    server.start()
    print("=" * 60)
    print(f"  gRPC Microservices Server started on port {port}")
    print(f"  Bind address: {bind_address}")
    print(f"  Max workers: {max_workers}")
    print(f"  Services: AuthService, DataService")
    print(f"  Mode: INSECURE (development)")
    print("=" * 60)
    print()
    print("Seeded users:")
    for username, user in store.users.items():
        print(f"  - {username} (ID: {user['user_id']})")
    print()

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        print("\n[Server] Shutting down gracefully...")
        event = server.stop(grace=5)
        event.wait()
        print("[Server] Server stopped.")


