# ============================================================
# Main entry point
# ============================================================

if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(description="gRPC Microservices")
    parser.add_argument(
        "mode",
        choices=["server", "client", "compile"],
        help="Run mode: 'server' to start the gRPC server, "
        "'client' to run the demo client, "
        "'compile' to compile proto files only",
    )
    parser.add_argument(
        "--port", type=int, default=50051, help="Server port (default: 50051)"
    )
    parser.add_argument(
        "--host", type=str, default="localhost", help="Server host for client (default: localhost)"
    )
    parser.add_argument(
        "--workers",
        type=int,
        default=10,
        help="Max worker threads (default: 10)",
    )

    args = parser.parse_args()

    if args.mode == "compile":
        compile_proto()
    elif args.mode == "server":
        serve(port=args.port, max_workers=args.workers)
    elif args.mode == "client":
        run_client_demo()